#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

#define MAXV 100000

static int leftChild[MAXV + 1];
static int rightChild[MAXV + 1];
static int isChild[MAXV + 1];
static int existsNode[MAXV + 1];
static int nodeList[10005];
static int nodeCnt;

int isBSTUtil(int val, long long minVal, long long maxVal) {
    if (val == 0) return 1; // null represented by 0
    if (val <= minVal || val >= maxVal) return 0;
    int l = leftChild[val];
    int r = rightChild[val];
    return isBSTUtil(l, minVal, val) && isBSTUtil(r, val, maxVal);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // reset arrays for values that will be used
        nodeCnt = 0;
        for (int i = 0; i < N-1; ++i) {
            int p, c; char dir; scanf("%d %d %c", &p, &c, &dir);
            leftChild[p] = rightChild[p] = 0; // ensure cleared
            leftChild[c] = rightChild[c] = 0;
            if (dir == 'L') leftChild[p] = c; else rightChild[p] = c;
            isChild[c] = 1;
            if (!existsNode[p]) { existsNode[p] = 1; nodeList[nodeCnt++] = p; }
            if (!existsNode[c]) { existsNode[c] = 1; nodeList[nodeCnt++] = c; }
        }
        if (N == 1) {
            // No edges, single node – always a BST
            printf("YES\n");
        } else {
            int root = 0;
            for (int i = 0; i < nodeCnt; ++i) {
                int v = nodeList[i];
