#include <bits/stdc++.h>
using namespace std;

bool checkBST(int node, long long lo, long long hi,
              const unordered_map<int,int>& L,
              const unordered_map<int,int>& R) {
    if (node == 0) return true;
    if (node <= lo || node >= hi) return false;
    int l = L.count(node) ? L.at(node) : 0;
    int r = R.count(node) ? R.at(node) : 0;
    return checkBST(l, lo, node, L, R) && checkBST(r, node, hi, L, R);
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        unordered_map<int,int> left, right;
        unordered_set<int> children, all;
        for(int i=0;i<N-1;++i){
            int p,c; char dir; cin>>p>>c>>dir;
            all.insert(p); all.insert(c);
            if(dir=='L') left[p]=c; else right[p]=c;
            children.insert(c);
        }
        if(N==1){
            cout<<"YES\n";
            continue;
        }
        int root=0;
        for(int v: all) if(!children.count(v)){ root=v; break; }
        bool ok = checkBST(root, LLONG_MIN, LLONG_MAX, left, right);
        cout<<(ok?"YES":"NO")<<'\n';
    }
    return 0;
}

