import java.io.*;
import java.util.*;

public class Main {
    static boolean dfs(int node, long lo, long hi,
                       Map<Integer,Integer> left,
                       Map<Integer,Integer> right) {
        if (node == 0) return true;
        if (node <= lo || node >= hi) return false;
        int l = left.getOrDefault(node, 0);
        int r = right.getOrDefault(node, 0);
        return dfs(l, lo, node, left, right) && dfs(r, node, hi, left, right);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Map<Integer,Integer> left = new HashMap<>();
            Map<Integer,Integer> right = new HashMap<>();
            Set<Integer> children = new HashSet<>();
            Set<Integer> all = new HashSet<>();
            for (int i = 0; i < N-1; ++i) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char dir = st.nextToken().charAt(0);
                all.add(p); all.add(c);
                if (dir == 'L') left.put(p, c); else right.put(p, c);
                children.add(c);
            }
            if (N == 1) {
                System.out.println("YES");
                continue;
            }
            int root = 0;
            for (int v : all) if (!children.contains(v)) { root = v; break; }
            boolean ok = dfs(root, Long.MIN_VALUE, Long.MAX_VALUE, left, right);
            System.out.println(ok ? "YES" : "NO");
        }
    }
}

