import sys

def is_bst(node, lo, hi, left, right):
    if node == 0:
        return True
    if not (lo < node < hi):
        return False
    return is_bst(left.get(node, 0), lo, node, left, right) and is_bst(right.get(node, 0), node, hi, left, right)

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        left = {}
        right = {}
        children = set()
        all_nodes = set()
        for __ in range(N-1):
            p = int(next(it)); c = int(next(it)); dir = next(it)
            all_nodes.add(p); all_nodes.add(c)
            if dir == 'L':
                left[p] = c
            else:
                right[p] = c
            children.add(c)
        if N == 1:
            out_lines.append('YES')
            continue
        root = next(v for v in all_nodes if v not in children)
        ok = is_bst(root, -10**18, 10**18, left, right)
        out_lines.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

